import{n as e,t}from"./jsx-runtime-DTJ6URaS.js";import{n,t as r}from"./PsychedelicBackground-DuBJkzT7.js";e();var i=t(),a=()=>(0,i.jsx)(r,{children:(0,i.jsxs)(n,{title:`8 Security Principles EVERY Software Dev Should Know`,shortRef:`security`,children:[(0,i.jsx)(`p`,{children:`It doesn't matter if you're frontend, backend, or a DevOps engineer. You should know these fundamentals.`}),(0,i.jsx)(`h3`,{children:`1. SQL injections: the Most Common Attack`}),(0,i.jsx)(`p`,{children:`Cyber attacks are so hot right now. SQL injections are the most common kind. It's an attempt to send commands directly to your database.`}),(0,i.jsxs)(`p`,{children:[`This doesn't mean they're just changing numbers in the backend. It's biggest danger is slipping in a `,(0,i.jsx)(`a`,{href:`https://stackoverflow.com/questions/332365/how-does-the-sql-injection-from-the-bobby-tables-xkcd-comic-work`,rel:`noreferrer noopener`,target:`_blank`,children:`DROP TABLES`}),` and losing literally all of your data forever (unless you had separate backups).`]}),(0,i.jsxs)(`p`,{children:[`The solution is simple: `,(0,i.jsx)(`b`,{children:`sanitize your inputs`}),`. How this works is different in each language or framework. Google your target language + "sanitize inputs" to learn how.`]}),(0,i.jsx)(`h3`,{children:`2. Cross-Site Scripting (XSS)`}),(0,i.jsx)(`p`,{children:`Sanitizing inputs doesn't just protect your database, but prevents another kind of attack: cross-site scripting. In this one, instead of sliding in a database command, a malicious actor sends code for your server to execute.`}),(0,i.jsx)(`p`,{children:`XSS can happen on your browser or server side, and the attacks can be anything that code can execute.`}),(0,i.jsxs)(`p`,{children:[`Don't worry about understanding all the ways it can hurt you as much as you're making sure you're simply `,(0,i.jsx)(`b`,{children:`sanitizing inputs`}),`.`]}),(0,i.jsx)(`h3`,{children:`3. Never, ever, EVER store plaintext passwords`}),(0,i.jsx)(`p`,{children:`I love to help out startups. If someone asks me to demo their app, I'm in. However, one thing will make me never want to help you again.`}),(0,i.jsx)(`p`,{children:`I tried an app and it didn't work for me. Okay, that's fine. Then a couple of weeks later, I got an email saying "in case you forgot your password, here it is!" That tells me they don't have serious developers working on their team (and also a good reminder for me to never to re-use passwords). I let them know their mistake.`}),(0,i.jsxs)(`p`,{children:[`A password should `,(0,i.jsx)(`b`,{children:(0,i.jsx)(`i`,{children:`only`})}),` be stored hashed. A hash is a one-way algorithm that spits out a random-looking string of characters. Hashes can't be reverse-engineered, but the same inputs into the hash will always create the same output of characters. So exposing a hash shouldn't create a security risk.`]}),(0,i.jsx)(`p`,{children:`The only exception to this is if the hash and salt (one input to the hash) are also exposed. Then, a hacker can input random words until it generates a hash that matches yours. Then they know your passwordâ€”another reminder to use random letters, numbers, and symbols in your passwords and not dictionary words.`}),(0,i.jsxs)(`p`,{children:[`Basically, just look up `,(0,i.jsx)(`code`,{children:`bcrypt`}),`, learn how it works, and use that `,(0,i.jsx)(`b`,{children:(0,i.jsx)(`i`,{children:`every time`})}),` when storing passwords.`]}),(0,i.jsx)(`h3`,{children:`4. Never hardcode your access keys`}),(0,i.jsxs)(`p`,{children:[`This is a very junior error to make, but it still happens so it's worth mentioning.`,(0,i.jsx)(`br`,{}),`NEVER hardcode any access keys (e.g. to AWS or another cloud environment). These should `,(0,i.jsx)(`i`,{children:`always`}),` always live in your `,(0,i.jsx)(`code`,{children:`.env`}),` environment variables file.`,(0,i.jsx)(`br`,{})]}),(0,i.jsx)(`p`,{children:`Out of all of these security vulnerabilities, this is potentially the most expensive error you can make.`}),(0,i.jsxs)(`h3`,{children:[`5. Run `,(0,i.jsx)(`code`,{children:`npm audit`}),` periodically`]}),(0,i.jsxs)(`p`,{children:[`This is a simple, built-in tool that helps you surface any known security vulnerabilities and the level of severity. There are similar ones in your target language (e.g. `,(0,i.jsx)(`code`,{children:`cargo audit`}),` in Rust).`]}),(0,i.jsx)(`h3`,{children:`6. Review open source code before your use it`}),(0,i.jsxs)(`p`,{children:[`Almost nobody does this. `,(0,i.jsx)(`a`,{href:`https://thehackernews.com/2022/07/over-1200-npm-packages-found-involved.html`,target:`_blank`,rel:`noreferrer noopener`,children:`The results can be hilarious.`}),` Realistically, the more known the maintainer, the safer it's going to be. The more a piece of open source is regularly used (judging by the weekly downloads chart on its NPM site) the more vetted it will be.`]}),(0,i.jsxs)(`p`,{children:[(0,i.jsx)(`b`,{children:`This is not the same as a security audit.`}),` If you're going to users credit card info, don't try it until you know for a fact what kind of software you're using.`]}),(0,i.jsx)(`h3`,{children:`7. Authenticate your Endpoints`}),(0,i.jsx)(`p`,{children:`Unless it's a simple GET request for public data, guard your endpoints with authentication middleware. That could be an authentication token, a session cookie, whatever. But anything to do with creating or deleting data needs authentication. Never expose any POST, PUT or DELETE methods without knowing which user is doing it.`}),(0,i.jsx)(`h3`,{children:`8. Principle of Least Privilege (POLP)`}),(0,i.jsx)(`p`,{children:`Speaking of knowing what your users are doing, each user needs the minimum security required to do their job. Whether their job is to post photos of their dog, or manage the database, each only needs the minimum amount of ability to access your application.`}),(0,i.jsx)(`p`,{children:`A user does not need to access the admin panel. A develop doesn't (usually) need to access the production database. A database manager doesn't need access to user passwords (which should be hashed anyway, right?).`}),(0,i.jsx)(`p`,{children:`This isn't about trust (just kidding, it definitely is), but minimizing unnecessary risks. A user trying to delete a photo should only be able to delete their own photos, no one else's. A developer shouldn't be able to accidentally force-push their branch to master.`})]})});export{a as default};